import React, { useState, useCallback, useRef } from 'react';
import UploadComponent from './components/UploadComponent';
import CompressionControls from './components/CompressionControls';
import ResultPreview from './components/ResultPreview';
import { compressImageToTargetSize, dataUrlToFile } from './utils/compression';
import './App.css';

function App() {
  const [originalImage, setOriginalImage] = useState(null);
  const [compressedImage, setCompressedImage] = useState(null);
  const [originalSize, setOriginalSize] = useState(0);
  const [compressedSize, setCompressedSize] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const [isCompressing, setIsCompressing] = useState(false);
  const [error, setError] = useState('');
  const [compressionQuality, setCompressionQuality] = useState(0.8);
  const [targetSizeKB, setTargetSizeKB] = useState('');
  const [fileName, setFileName] = useState('');
  const [originalFileName, setOriginalFileName] = useState('');
  const [compressionInfo, setCompressionInfo] = useState(null);
  const fileInputRef = useRef(null);

  const formatFileSize = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const calculateCompressionPercentage = () => {
    if (originalSize === 0) return 0;
    return ((originalSize - compressedSize) / originalSize * 100).toFixed(1);
  };

  const handleFileSelect = (file) => {
    setError('');
    setCompressedImage(null);
    setCompressedSize(0);
    setCompressionInfo(null);

    const reader = new FileReader();
    reader.onload = (e) => {
      setOriginalImage(e.target.result);
      setOriginalSize(file.size);

      // Extract file name without extension
      const nameWithoutExt = file.name.replace(/\.[^/.]+$/, '');
      setOriginalFileName(nameWithoutExt);
      setFileName(nameWithoutExt);
    };
    reader.readAsDataURL(file);
  };

  const compressImage = async () => {
    if (!originalImage) return;

    setIsCompressing(true);
    setError('');
    setCompressionInfo(null);

    try {
      // Convert data URL to File
      const response = await fetch(originalImage);
      const blob = await response.blob();
      const file = new File([blob], originalFileName + '.jpg', { type: blob.type });

      const targetSize = targetSizeKB ? parseInt(targetSizeKB) : null;
      const result = await compressImageToTargetSize(file, targetSize, compressionQuality);

      setCompressedImage(result.dataUrl);
      setCompressedSize(result.file.size);
      setCompressionInfo(result);

      // Show warning if target size wasn't achieved
      (!result.achievedTarget && targetSize) && setError(
        `Could not achieve exact target size of ${targetSizeKB}KB. Closest result: ${Math.round(result.file.size / 1024)}KB`
      );

    } catch (err) {
      if (err.message.includes('Unable to compress')) {
        setError('Target size is too small. Try a larger target size or reduce quality.');
      } else {
        setError('Failed to compress image. Please try again.');
      }
      console.error('Compression error:', err);
    } finally {
      setIsCompressing(false);
    }
  };

  const downloadImage = async () => {
    if (!compressedImage) return;

    try {
      const file = await dataUrlToFile(compressedImage, fileName + '.jpg');
      const link = document.createElement('a');
      link.href = URL.createObjectURL(file);
      link.download = file.name;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(link.href);
    } catch (error) {
      setError('Failed to download image. Please try again.');
      console.error('Download error:', error);
    }
  };

  const reset = () => {
    setOriginalImage(null);
    setCompressedImage(null);
    setOriginalSize(0);
    setCompressedSize(0);
    setError('');
    setFileName('');
    setOriginalFileName('');
    setTargetSizeKB('');
    setCompressionInfo(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <div className="container mx-auto px-4 py-8 max-w-4xl">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-gray-800 mb-2">Image Compressor Tool</h1>
          <p className="text-gray-600">Compress your images online for free. Fast, secure, and works entirely in your browser.</p>
        </header>

        <main className="card p-6 md:p-8">
          {!originalImage ? (
            <UploadComponent
              onFileSelect={handleFileSelect}
              isDragging={isDragging}
              setIsDragging={setIsDragging}
            />
          ) : (
            <div className="space-y-6">
              <ResultPreview
                originalImage={originalImage}
                compressedImage={compressedImage}
                originalSize={originalSize}
                compressedSize={compressedSize}
                fileName={fileName}
                setFileName={setFileName}
                onDownload={downloadImage}
                onReset={reset}
              />

              {!compressedImage && (
                <CompressionControls
                  compressionQuality={compressionQuality}
                  setCompressionQuality={setCompressionQuality}
                  targetSizeKB={targetSizeKB}
                  setTargetSizeKB={setTargetSizeKB}
                  onCompress={compressImage}
                  isCompressing={isCompressing}
                  hasOriginalImage={!!originalImage}
                  hasCompressedImage={!!compressedImage}
                />
              )}
            </div>
          )}

          {error && (
            <div className="mt-4 bg-red-50 border border-red-200 rounded-lg p-4">
              <p className="text-red-800 text-sm">{error}</p>
            </div>
          )}
        </main>

        <footer className="text-center mt-8 text-gray-600 text-sm">
          <p>Your images are processed locally in your browser. No data is sent to any server.</p>
        </footer>
      </div>
    </div>
  );
}

export default App;
